class Solution:
    def getSmallestString(self, s):
        s = list(s)
        for i in range(len(s) - 1):
            a, b = int(s[i]), int(s[i+1])
            if a % 2 == b % 2 and a > b:
                s[i], s[i+1] = s[i+1], s[i]
                return ''.join(s)
        return ''.join(s)

