var getSmallestString = function(s) {
    const arr = s.split('');
    for (let i = 0; i < arr.length - 1; i++) {
        const a = parseInt(arr[i]), b = parseInt(arr[i+1]);
        if (a % 2 === b % 2 && a > b) {
            arr[i] = String(b);
            arr[i+1] = String(a);
            return arr.join('');
        }
    }
    return s;
};
